import { readFile, writeFile } from 'fs/promises';
import { join } from 'path';
async function updateConfig(): Promise<void> {
  try {
    // Read the file as a string with UTF-8 encoding
    const filePath: string = join(__dirname, 'config.json');
    const data: string = await readFile(filePath, 'utf-8');
    // Parse JSON string into an object
    const config: Record<string, unknown> = JSON.parse(data);
    // Update a property
    config.theme = 'dark' as unknown;
    // Write back as formatted JSON
    await writeFile(filePath, JSON.stringify(config, null, 2), 'utf-8');
    console.log('Config updated successfully');
  } catch (error: unknown) {
    if (error instanceof Error) {
      console.error('File operation failed:', error.message);
    }
  }
}
updateConfig();
// Expected: Config updated successfully (or error message if file missing)
